<script setup lang="ts">
import { onMounted, reactive, ref, watch } from "vue";
import { ElMessage, ElMessageBox } from "element-plus";
import { api, type ApplicationItem, type TeamMemberItem, type TeamSummary, type VirtualApiKeyItem } from "../api";
const props = defineProps<{ defaultTeamId?: number | null; defaultMemberId?: number | null }>();
const keys = ref<VirtualApiKeyItem[]>([]); const total = ref(0); const teams = ref<TeamSummary[]>([]); const members = ref<TeamMemberItem[]>([]); const apps = ref<ApplicationItem[]>([]); const teamModels = ref<string[]>([]); const loading = ref(false); const createDialog = ref(false); const revealDialog = ref(false); const revealed = ref("");
const filters = reactive({ keyword: "", teamId: undefined as number | undefined, applicationId: undefined as number | undefined, memberId: undefined as number | undefined, enabled: "", expiry: "", page: 0, size: 10 }); const form = reactive({ teamId: 0, memberId: 0, applicationId: 0, name: "", allowedModels: [] as string[], expiresAt: "" });
async function load(reset = false) { if (reset) filters.page = 0; loading.value = true; try { const result = await api.keys({ ...filters, enabled: filters.enabled || null }); keys.value = result.items; total.value = result.total; } catch (e) { ElMessage.error(e instanceof Error ? e.message : "Key 列表加载失败"); } finally { loading.value = false; } }
async function loadTeams() { const result = await api.teams({ page: 0, size: 100 }); teams.value = result.items; }
async function loadFilterScope(teamId?: number) { filters.applicationId = undefined; filters.memberId = undefined; members.value = []; apps.value = []; if (!teamId) return; const [memberData, appData] = await Promise.all([api.members(teamId), api.applications(teamId)]); members.value = memberData.items; apps.value = appData.items; }
async function loadCreateScope(teamId: number) { form.teamId = teamId; form.memberId = 0; form.applicationId = 0; const [memberData, appData, access] = await Promise.all([api.members(teamId), api.applications(teamId), api.teamModels(teamId)]); members.value = memberData.items.filter(item => item.enabled); apps.value = appData.items; teamModels.value = access.logicalModels; form.allowedModels = [...teamModels.value]; }
function applyIdentityScope() { filters.teamId = props.defaultTeamId ?? undefined; filters.memberId = props.defaultMemberId ?? undefined; filters.applicationId = undefined; filters.page = 0; }
function clear() { Object.assign(filters, { keyword: "", teamId: props.defaultTeamId ?? undefined, applicationId: undefined, memberId: props.defaultMemberId ?? undefined, enabled: "", expiry: "", page: 0 }); members.value = []; apps.value = []; void load(); }
async function openCreate() { Object.assign(form, { teamId: 0, memberId: 0, applicationId: 0, name: "", allowedModels: [], expiresAt: "" }); createDialog.value = true; if (teams.value[0]) await loadCreateScope(teams.value[0].teamId); }
async function create() { try { const result = await api.createMemberKey(form.teamId, form.memberId, { applicationId: form.applicationId, name: form.name, allowedModels: form.allowedModels, expiresAt: form.expiresAt || null }); createDialog.value = false; revealed.value = result.apiKey; revealDialog.value = true; await load(); } catch (e) { ElMessage.error(e instanceof Error ? e.message : "创建失败"); } }
async function disable(key: VirtualApiKeyItem) { try { await ElMessageBox.confirm(`停用 ${key.name} 后，现有请求会被拒绝且缓存立即失效。`, "确认停用虚拟 Key", { type: "warning", confirmButtonText: "停用", cancelButtonText: "取消" }); await api.disableKey(key.keyId); ElMessage.success("Key 已停用"); await load(); } catch (e) { if (e !== "cancel" && e !== "close") ElMessage.error(e instanceof Error ? e.message : "停用失败"); } }
async function copy() { await navigator.clipboard.writeText(revealed.value); ElMessage.success("Key 已复制"); }
watch(() => filters.teamId, value => { void loadFilterScope(value); });
watch([() => props.defaultTeamId, () => props.defaultMemberId], () => { applyIdentityScope(); void load(); });
onMounted(async () => { applyIdentityScope(); await Promise.all([loadTeams(), load()]); });
</script>
<template><section class="page-stack" v-loading="loading"><header class="page-heading"><div><p class="eyebrow">Gateway credentials</p><h1>虚拟 API Key</h1><p>按团队、应用和成员分发独立调用凭据；明文只在创建后显示一次。</p></div><el-button type="primary" @click="openCreate">分发虚拟 Key</el-button></header><section class="surface"><el-form inline class="search-bar" @submit.prevent="load(true)"><el-input v-model="filters.keyword" placeholder="名称或 Key 前缀" clearable/><el-select v-model="filters.teamId" placeholder="团队" clearable><el-option v-for="team in teams" :key="team.teamId" :label="team.name" :value="team.teamId"/></el-select><el-select v-model="filters.applicationId" placeholder="应用" clearable><el-option v-for="app in apps" :key="app.applicationId" :label="app.name" :value="app.applicationId"/></el-select><el-select v-model="filters.memberId" placeholder="成员" clearable><el-option v-for="member in members" :key="member.memberId" :label="member.name" :value="member.memberId"/></el-select><el-select v-model="filters.enabled" placeholder="状态" clearable><el-option label="启用" value="true"/><el-option label="已停用" value="false"/></el-select><el-select v-model="filters.expiry" placeholder="到期状态" clearable><el-option label="有效期内" value="ACTIVE"/><el-option label="已过期" value="EXPIRED"/></el-select><el-button type="primary" native-type="submit">搜索</el-button><el-button @click="clear">重置</el-button></el-form><el-table :data="keys"><el-table-column prop="name" label="名称" min-width="140"/><el-table-column prop="keyPrefix" label="前缀" min-width="150"/><el-table-column prop="teamName" label="团队"/><el-table-column prop="applicationName" label="应用"/><el-table-column prop="ownerMemberName" label="成员"/><el-table-column label="允许模型" min-width="160"><template #default="scope">{{ scope.row.allowedModels.join('，') }}</template></el-table-column><el-table-column label="到期" width="170"><template #default="scope">{{ scope.row.expiresAt || '永久有效' }}</template></el-table-column><el-table-column label="状态" width="95"><template #default="scope"><el-tag :type="scope.row.enabled ? 'success' : 'info'">{{ scope.row.enabled ? '启用' : '停用' }}</el-tag></template></el-table-column><el-table-column label="操作" width="85"><template #default="scope"><el-button v-if="scope.row.enabled" type="danger" text @click="disable(scope.row)">停用</el-button></template></el-table-column></el-table><el-pagination class="table-pagination" background layout="total, prev, pager, next" :total="total" :page-size="filters.size" :current-page="filters.page + 1" @current-change="page => { filters.page = page - 1; load(); }"/></section><el-dialog v-model="createDialog" title="分发虚拟 API Key" width="540px" :close-on-click-modal="false"><el-alert type="warning" :closable="false" title="Key 明文仅在创建成功后显示一次。"/><el-form label-position="top" class="form-divider"><el-form-item label="团队"><el-select :model-value="form.teamId" @update:model-value="loadCreateScope"><el-option v-for="team in teams" :key="team.teamId" :label="team.name" :value="team.teamId"/></el-select></el-form-item><el-form-item label="成员"><el-select v-model="form.memberId"><el-option v-for="member in members" :key="member.memberId" :label="member.name" :value="member.memberId"/></el-select></el-form-item><el-form-item label="应用"><el-select v-model="form.applicationId"><el-option v-for="app in apps" :key="app.applicationId" :label="app.name" :value="app.applicationId"/></el-select></el-form-item><el-form-item label="Key 名称"><el-input v-model="form.name" placeholder="例如 cli-local"/></el-form-item><el-form-item label="允许模型"><el-checkbox-group v-model="form.allowedModels" class="checkbox-stack"><el-checkbox v-for="model in teamModels" :key="model" :label="model">{{ model }}</el-checkbox></el-checkbox-group></el-form-item><el-form-item label="到期时间（可选）"><el-input v-model="form.expiresAt" placeholder="2026-12-31T23:59:59+08:00"/></el-form-item></el-form><template #footer><el-button @click="createDialog = false">取消</el-button><el-button type="primary" :disabled="!form.teamId || !form.memberId || !form.applicationId || !form.name || !form.allowedModels.length" @click="create">创建 Key</el-button></template></el-dialog><el-dialog v-model="revealDialog" title="立即保存虚拟 Key" width="580px" :close-on-click-modal="false"><div class="secret-reveal"><p>此明文关闭后将不可恢复。</p><code>{{ revealed }}</code><el-button @click="copy">复制 Key</el-button></div><template #footer><el-button type="primary" @click="revealDialog = false; revealed = ''">我已安全保存</el-button></template></el-dialog></section></template>
